package com.google.gson.internal.reflect;

import static org.junit.jupiter.api.Assertions.*;

import java.lang.reflect.Field;
import java.lang.reflect.Method;

import org.junit.jupiter.api.BeforeAll;
import org.junit.jupiter.api.Test;

import static org.mockito.Mockito.*;

class ReflectionHelperTest {

  private static Object dummyRecordHelper;
  private static Method dummyMethod;
  private static Field dummyField;
  private static Field recordHelperField;

  @BeforeAll
  static void setup() throws Exception {
    dummyField = DummyClass.class.getDeclaredField("value");
    dummyMethod = DummyClass.class.getDeclaredMethod("getValue");

    recordHelperField = ReflectionHelper.class.getDeclaredField("RECORD_HELPER");
    recordHelperField.setAccessible(true);

    // Get the type of RECORD_HELPER field (RecordHelper)
    Class<?> recordHelperClass = recordHelperField.getType();

    // Create a Mockito mock instance of RecordHelper
    dummyRecordHelper = mock(recordHelperClass);

    // When getAccessor is called with any Class and Field, return dummyMethod
    Method getAccessorMethod = recordHelperClass.getMethod("getAccessor", Class.class, Field.class);
    when(getAccessorMethod.invoke(dummyRecordHelper, DummyClass.class, dummyField)).thenReturn(dummyMethod);

    // Mockito's when().thenReturn() does not work with reflection invoke directly,
    // so use Mockito's stub for method call on mock:
    // Instead, use Mockito's 'doAnswer' with invocation handler:
    // But since we have no direct interface, use a dynamic proxy that delegates to Mockito.
    // Alternatively, use a Mockito spy with Answer.

    // Because the above does not work, instead create a dynamic proxy that intercepts getAccessor call:
    dummyRecordHelper = java.lang.reflect.Proxy.newProxyInstance(
        recordHelperClass.getClassLoader(),
        new Class<?>[]{recordHelperClass},
        (proxy, method, args) -> {
          if ("getAccessor".equals(method.getName()) && args.length == 2) {
            return dummyMethod;
          }
          if (method.getReturnType().isPrimitive()) {
            if (method.getReturnType() == boolean.class) return false;
            if (method.getReturnType() == void.class) return null;
            return 0;
          }
          return null;
        });
  }

  @Test
  void getAccessor_returnsMethodFromRecordHelper() throws Exception {
    Object originalRecordHelper = recordHelperField.get(null);
    try {
      recordHelperField.set(null, dummyRecordHelper);

      Method result = ReflectionHelper.getAccessor(DummyClass.class, dummyField);
      assertNotNull(result);
      assertEquals(dummyMethod, result);
    } finally {
      recordHelperField.set(null, originalRecordHelper);
    }
  }

  private static class DummyClass {
    private int value;

    public int getValue() {
      return value;
    }
  }
}
